const payload = $input.first().json.body ?? $input.first().json;
const metadata = payload.metadata && typeof payload.metadata === 'object' ? payload.metadata : {};
const category = payload.category || (Array.isArray(metadata.categories) && metadata.categories[0]) || 'Umum';
const scheduledTime = payload.scheduledTime || '';
const slots = scheduledTime ? [{ time: scheduledTime, label: 'Scheduled Upload' }] : [];
const renderWebhookUrl = metadata.renderWebhookUrl || '';

if (!payload.jobId) {
  throw new Error('jobId wajib dikirim dari server VidGen.');
}

if (!payload.prompt) {
  throw new Error('prompt wajib dikirim dari server VidGen.');
}

return [{
  json: {
    ...payload,
    metadata,
    category,
    slots,
    renderWebhookUrl,
    callbackHeaders: {
      'Content-Type': 'application/json',
      'x-vidgen-callback-secret': payload.callbackSecret || ''
    },
    generatePayload: {
      desc: payload.prompt || payload.title,
      selectedStyles: Array.isArray(metadata.styles) ? metadata.styles : [],
      selectedCats: Array.isArray(metadata.categories) && metadata.categories.length ? metadata.categories : (category ? [category] : []),
      mood: metadata.mood || '',
      camera: metadata.camera || '',
      slots
    }
  }
}];

