const source = $('Normalize Request').first().json;
const response = $input.first().json;
const productionPrompt = response.text || '';

if (!productionPrompt) {
  throw new Error('Respons /api/generate kosong.');
}

const lines = productionPrompt.split('\n').map((line) => line.trim()).filter(Boolean);
const probableTitle = lines.find((line) => /^judul/i.test(line)) || source.title || 'Video tanpa judul';
const thumbnailPrompt = `${source.category || 'Video'} thumbnail, bold headline, cinematic, high click-through`;

return [{
  json: {
    ...source,
    productionPrompt,
    probableTitle,
    thumbnailPrompt,
    outputs: {
      productionPrompt,
      generatedAt: new Date().toISOString(),
      source: 'automation.maksitech.id/api/generate'
    }
  }
}];

return [{
  json: {
    ...$input.first().json,
    renderPayload: {
      jobId: $json.jobId,
      title: $json.probableTitle,
      topic: $json.title,
      category: $json.category,
      prompt: $json.productionPrompt,
      source: $json.source,
      metadata: $json.metadata,
      callbackUrl: $json.callbackUrl,
      callbackSecret: $json.callbackSecret,
      requestedAt: new Date().toISOString()
    }
  }
}];

const source = $('Prepare Render Payload').first().json;
const renderResult = $input.first().json || {};

return [{
  json: {
    ...source,
    status: 'completed',
    message: 'Paket produksi dan render video selesai diproses.',
    finalVideoUrl: renderResult.finalVideoUrl || renderResult.videoUrl || '',
    shortVideoUrl: renderResult.shortVideoUrl || '',
    thumbnailUrl: renderResult.thumbnailUrl || '',
    youtubeUrl: renderResult.youtubeUrl || '',
    outputs: {
      ...source.outputs,
      renderResponse: renderResult
    }
  }
}];

const source = $input.first().json;
return [{
  json: {
    ...source,
    status: 'completed',
    message: 'Paket produksi selesai. Render video belum dijalankan karena renderWebhookUrl belum diisi.'
  }
}];
